function ProgressBar({ value, max, color }) {
  const pct = max === 0 ? 0 : Math.min(100, Math.round((value / max) * 100));
  return (
    <div style={{ background:"#e9ecef", borderRadius:8, height:10, overflow:"hidden" }}>
      <div style={{ width:`${pct}%`, background:color, height:"100%", borderRadius:8, transition:"width 0.4s ease" }} />
    </div>
  );
}
function Badge({ children, color="#117a65" }) {
  return <span style={{ background:color+"22", color, border:`1px solid ${color}55`, borderRadius:6, padding:"2px 8px", fontSize:12, fontWeight:600, display:"inline-block" }}>{children}</span>;
}

