function FlashcardsTab({ addXP, flashcardsStudied, setFlashcardsStudied, lang, logPerformance, logFeel }) {
  const [filterTopic, setFilterTopic] = useState("all");
  const [cardIdx, setCardIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [done, setDone] = useState([]);
  const [sessionCorrect, setSessionCorrect] = useState(0);
  const [sessionTotal, setSessionTotal] = useState(0);
  const [showFeel, setShowFeel] = useState(false);
  const [feelDone, setFeelDone] = useState(false);
  const T = UI[lang];
  const isAfr = lang !== "eng";
  const filtered = filterTopic==="all" ? ALL_FLASHCARDS : ALL_FLASHCARDS.filter(f=>f.topic===filterTopic);
  const card = filtered[cardIdx];
  const topic = TOPICS.find(t=>t.id===card?.topic);
  const getQ = c => lang==="eng" ? c.q : c.qAfr;
  const getA = c => lang==="eng" ? c.a : c.aAfr;

  // Trigger feel prompt after completing a full round
  const FEEL_THRESHOLD = Math.min(8, filtered.length);

  const next = (knew) => {
    const topicId = card?.topic;
    if (topicId) logPerformance(topicId, knew);
    if (knew) { addXP(5); setFlashcardsStudied(p=>p+1); setSessionCorrect(c=>c+1); }
    const newTotal = sessionTotal + 1;
    setSessionTotal(newTotal);
    if (!done.includes(cardIdx)) setDone(p=>[...p,cardIdx]);
    // Show feel prompt after threshold cards if not yet shown this session
    if (newTotal >= FEEL_THRESHOLD && !feelDone && !showFeel) {
      setTimeout(() => setShowFeel(true), 300);
    }
    setFlipped(false);
    setTimeout(()=>setCardIdx(i=>(i+1)%filtered.length), 150);
  };

  const handleFeel = (feel) => {
    // Log feel against the current topic (or "all" session — use most-practised topic)
    const topicCounts = {};
    filtered.forEach(c => { topicCounts[c.topic] = (topicCounts[c.topic]||0)+1; });
    const dominantTopic = Object.entries(topicCounts).sort((a,b)=>b[1]-a[1])[0]?.[0];
    if (dominantTopic) logFeel(feel, dominantTopic);
    setShowFeel(false);
    setFeelDone(true);
    addXP(2);
  };

  const resetSession = () => {
    setCardIdx(0); setFlipped(false); setDone([]);
    setSessionCorrect(0); setSessionTotal(0);
    setShowFeel(false); setFeelDone(false);
  };

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:17, marginBottom:4 }}>{T.flashTitle}</div>
      <div style={{ color:"#888", fontSize:13, marginBottom:12 }}>{T.flashSub}</div>
      <div style={{ display:"flex", gap:8, overflowX:"auto", paddingBottom:8, marginBottom:14 }}>
        <button onClick={()=>{setFilterTopic("all");resetSession();}} style={{ whiteSpace:"nowrap", padding:"6px 14px", borderRadius:20, border:"none", cursor:"pointer", background:filterTopic==="all"?"#1a3a5c":"#f0f0f0", color:filterTopic==="all"?"#fff":"#555", fontSize:13 }}>{T.all} ({ALL_FLASHCARDS.length})</button>
        {TOPICS.map(t=><button key={t.id} onClick={()=>{setFilterTopic(t.id);resetSession();}} style={{ whiteSpace:"nowrap", padding:"6px 11px", borderRadius:20, border:"none", cursor:"pointer", background:filterTopic===t.id?t.color:"#f0f0f0", color:filterTopic===t.id?"#fff":"#555", fontSize:12 }}>{t.emoji}</button>)}
      </div>
      <div style={{ textAlign:"center", fontSize:13, color:"#888", marginBottom:8 }}>{T.cardOf} {cardIdx+1} {T.of} {filtered.length} · {done.length} {T.done}</div>
      <ProgressBar value={done.length} max={filtered.length} color={topic?.color||"#1a5276"} />

      {/* ── SESSION FEEL PROMPT ── */}
      {showFeel && (
        <div style={{ background:"#1a3a5c", borderRadius:14, padding:18, marginTop:14, marginBottom:4 }}>
          <div style={{ fontWeight:700, color:"#fff", fontSize:15, marginBottom:4 }}>
            {isAfr ? "📡 Vinnige kontrole" : "📡 Quick check"}
          </div>
          <div style={{ color:"#a8c4d8", fontSize:13, marginBottom:14 }}>
            {isAfr
              ? `${sessionCorrect}/${sessionTotal} korrek tot dusver. Hoe voel hierdie werk vir jou?`
              : `${sessionCorrect}/${sessionTotal} correct so far. How does this material feel?`}
          </div>
          <div style={{ display:"flex", gap:10 }}>
            {[
              { feel:"lost", emoji:"😕", labelAfr:"Nog verward", labelEng:"Still confused", color:"#c0392b" },
              { feel:"ok",   emoji:"😐", labelAfr:"Besig om te leer", labelEng:"Getting there",  color:"#e67e22" },
              { feel:"got",  emoji:"😊", labelAfr:"Ek het dit!",     labelEng:"I've got it!",    color:"#117a65" },
            ].map(opt => (
              <button key={opt.feel} onClick={()=>handleFeel(opt.feel)} style={{ flex:1, background:"rgba(255,255,255,0.1)", border:`2px solid rgba(255,255,255,0.2)`, borderRadius:12, padding:"12px 6px", cursor:"pointer", textAlign:"center" }}>
                <div style={{ fontSize:26, marginBottom:4 }}>{opt.emoji}</div>
                <div style={{ fontSize:11, color:"#e8f0f8", fontWeight:600 }}>{isAfr?opt.labelAfr:opt.labelEng}</div>
              </button>
            ))}
          </div>
          <div style={{ fontSize:11, color:"#5580a0", marginTop:10, textAlign:"center" }}>
            {isAfr ? "+2 XP · Dit help die radar om jou swakste areas te vind" : "+2 XP · This helps the radar find your weakest areas"}
          </div>
        </div>
      )}

      {/* ── CARD ── */}
      {!showFeel && (
        <>
          <div onClick={()=>setFlipped(f=>!f)} style={{ marginTop:14, minHeight:220, background:flipped?(topic?.lightColor||"#eafaf1"):"#fff", border:`2px solid ${topic?.color||"#1a5276"}44`, borderRadius:18, padding:24, cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", textAlign:"center", transition:"background 0.2s" }}>
            {!flipped
              ? (<><div style={{ fontSize:12, color:"#aaa", marginBottom:14, letterSpacing:1 }}>❓ {T.question}</div><div style={{ fontWeight:700, fontSize:16, color:"#222", lineHeight:1.7 }}>{card&&getQ(card)}</div><div style={{ marginTop:16, fontSize:12, color:"#ccc" }}>{T.tapReveal}</div></>)
              : (<><div style={{ fontSize:12, color:topic?.color||"#117a65", fontWeight:700, marginBottom:12, letterSpacing:1 }}>✅ {T.answer}</div><div style={{ fontSize:14, color:"#333", lineHeight:1.9 }}>{card&&getA(card)}</div></>)
            }
          </div>
          {flipped && (
            <div style={{ display:"flex", gap:12, marginTop:14 }}>
              <button onClick={()=>next(false)} style={{ flex:1, background:"#ffeaea", border:"2px solid #c0392b33", color:"#c0392b", borderRadius:12, padding:14, cursor:"pointer", fontWeight:700, fontSize:14 }}>{T.didntKnow}</button>
              <button onClick={()=>next(true)} style={{ flex:1, background:"#eafaf1", border:"2px solid #117a6533", color:"#117a65", borderRadius:12, padding:14, cursor:"pointer", fontWeight:700, fontSize:14 }}>{T.gotIt}</button>
            </div>
          )}
          {!flipped && <button onClick={()=>{setFlipped(false);setCardIdx(i=>(i+1)%filtered.length);}} style={{ marginTop:12, width:"100%", background:"#f5f5f5", border:"none", borderRadius:12, padding:12, cursor:"pointer", color:"#888", fontSize:14 }}>{T.skip}</button>}
        </>
      )}

      {/* Session progress indicator */}
      {sessionTotal > 0 && !showFeel && (
        <div style={{ marginTop:12, display:"flex", gap:6, justifyContent:"center", alignItems:"center" }}>
          <span style={{ fontSize:11, color:"#aaa" }}>
            {isAfr ? `Sessie: ${sessionCorrect}/${sessionTotal}` : `Session: ${sessionCorrect}/${sessionTotal}`}
          </span>
          {feelDone && <span style={{ fontSize:11, color:"#117a65" }}>· 📡 {isAfr?"Radar opgedateer":"Radar updated"}</span>}
        </div>
      )}
    </div>
  );
}

