function AfrWoordeboek({ lang }) {
  const [filterTopic, setFilterTopic] = useState("all");
  const allTerms = TOPICS.flatMap(t=>t.bilingualTerms.map(term=>({...term,topicId:t.id,topicColor:t.color,topicEmoji:t.emoji})));
  const filtered = filterTopic==="all" ? allTerms : allTerms.filter(t=>t.topicId===filterTopic);
  return (
    <div>
      <div style={{ background:"#eaf2fb", border:"1px solid #1a527644", borderRadius:12, padding:12, marginBottom:14, fontSize:13, color:"#1a5276" }}>
        💡 {lang==="eng" ? "Every term in Afrikaans and English — both columns are needed for the exam." : "Elke term in Afrikaans en Engels — albei kolomme is nodig vir die eksamen."}
      </div>
      <div style={{ display:"flex", gap:8, overflowX:"auto", paddingBottom:8, marginBottom:14 }}>
        <button onClick={()=>setFilterTopic("all")} style={{ whiteSpace:"nowrap", padding:"6px 14px", borderRadius:20, border:"none", cursor:"pointer", background:filterTopic==="all"?"#1a3a5c":"#f0f0f0", color:filterTopic==="all"?"#fff":"#555", fontSize:13 }}>Alles</button>
        {TOPICS.map(t=><button key={t.id} onClick={()=>setFilterTopic(t.id)} style={{ whiteSpace:"nowrap", padding:"6px 11px", borderRadius:20, border:"none", cursor:"pointer", background:filterTopic===t.id?t.color:"#f0f0f0", color:filterTopic===t.id?"#fff":"#555", fontSize:13 }}>{t.emoji}</button>)}
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
        {filtered.map((t,i)=>(
          <div key={i} style={{ background:"#fff", border:`1px solid ${t.topicColor}33`, borderRadius:12, padding:14 }}>
            <div style={{ display:"flex", gap:10, marginBottom:6, flexWrap:"wrap", alignItems:"center" }}>
              <span>🇿🇦</span><span style={{ fontWeight:700, color:t.topicColor, fontSize:14 }}>{t.afr}</span>
              <span style={{ color:"#ddd" }}>↔</span>
              <span>🇬🇧</span><span style={{ fontWeight:700, color:"#444", fontSize:14 }}>{t.eng}</span>
            </div>
            <div style={{ fontSize:13, color:"#555", lineHeight:1.6 }}>{lang==="eng"?t.def:t.defAfr}</div>
            {lang==="bil" && <div style={{ fontSize:12, color:"#aaa", marginTop:4, fontStyle:"italic" }}>{t.def}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}

function AfrVraagwoorde({ lang }) {
  const isAfr = lang !== "eng";
  const verbs = [
    { afr:"Noem / Lys", eng:"Name / List", tip:"Gee net 'n lys — geen verduideliking nodig nie", tipEng:"Give a list only — no explanation needed", example:"Noem DRIE groepe wat deur die Nazis vervolg is." },
    { afr:"Omskryf / Definieer", eng:"Define", tip:"Gee die betekenis van die term presies", tipEng:"Give the exact meaning of the term", example:"Omskryf die woord 'propaganda'." },
    { afr:"Verduidelik", eng:"Explain", tip:"Gee besonderhede EN redes — meer as net 'n lys", tipEng:"Give detail AND reasons — more than just a list", example:"Verduidelik waarom die Groot Depressie Hitler gehelp het." },
    { afr:"Bespreek", eng:"Discuss", tip:"Skryf oor die onderwerp vanuit verskillende hoeke", tipEng:"Write about the topic from different angles", example:"Bespreek die oorsake van die Tweede Wêreldoorlog." },
    { afr:"Beskryf", eng:"Describe", tip:"Gee besonderhede van wat iets is of hoe dit lyk", tipEng:"Give details of what something is or looks like", example:"Beskryf die toestande in Duitsland na 1919." },
    { afr:"Evalueer", eng:"Evaluate", tip:"Beoordeel die belangrikheid — gee jou mening", tipEng:"Judge the importance — give your opinion", example:"Evalueer die rol van propaganda in Nazi-Duitsland." },
    { afr:"Vergelyk", eng:"Compare", tip:"Wys ooreenkomste EN verskille", tipEng:"Show similarities AND differences", example:"Vergelyk kapitalisme en kommunisme." },
    { afr:"Oorsake", eng:"Causes", tip:"HOEKOM het iets gebeur? Redes voor die gebeurtenis", tipEng:"WHY did it happen? Reasons before the event", example:"Wat was die oorsake van die Koue Oorlog?" },
    { afr:"Gevolge / Uitwerking", eng:"Effects / Consequences", tip:"Wat het gebeur AS GEVOLG? Redes ná die gebeurtenis", tipEng:"What happened AS A RESULT?", example:"Bespreek die gevolge van die Holocaust." },
    { afr:"Keerpunt", eng:"Turning point", tip:"Die oomblik waarop alles verander het", tipEng:"The moment when everything changed", example:"Waarom word Pearl Harbour as 'n keerpunt beskou?" },
    { afr:"Was dit geregverdig?", eng:"Was it justified?", tip:"Gee argumente VIR en TEEN — besluit dan self", tipEng:"Give arguments FOR and AGAINST — then decide", example:"Was die laat val van die atoombomme geregverdig?" },
    { afr:"Gebruik Bron ___ en jou eie kennis", eng:"Use Source ___ and your own knowledge", tip:"Gebruik inligting UIT die bron PLUS wat jy geleer het", tipEng:"Use info FROM the source PLUS your own knowledge", example:"Gebruik Bron A en jou eie kennis om vraag 1.3 te beantwoord." },
  ];
  return (
    <div>
      <div style={{ background:"#fff9e6", border:"1px solid #f0c04055", borderRadius:12, padding:12, marginBottom:14, fontSize:13, color:"#7d6608" }}>
        💡 {isAfr ? "Hierdie woorde vertel jou WAT om te doen. Kry hulle verkeerd en verloor punte selfs as jy die inhoud ken!" : "These words tell you WHAT to do. Get them wrong and you lose marks even if you know the content!"}
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
        {verbs.map((v,i)=>(
          <div key={i} style={{ background:"#fff", border:"1px solid #e0e0e0", borderRadius:12, padding:14 }}>
            <div style={{ display:"flex", gap:10, alignItems:"center", marginBottom:6, flexWrap:"wrap" }}>
              <span style={{ background:"#1a3a5c", color:"#fff", borderRadius:8, padding:"3px 10px", fontWeight:700, fontSize:13 }}>{v.afr}</span>
              <span style={{ color:"#aaa" }}>=</span>
              <span style={{ fontWeight:700, color:"#444", fontSize:14 }}>{v.eng}</span>
            </div>
            <div style={{ fontSize:13, color:"#555", marginBottom:4 }}>📌 {v.tip}</div>
            {lang!=="afr" && <div style={{ fontSize:12, color:"#aaa", marginBottom:6, fontStyle:"italic" }}>{v.tipEng}</div>}
            <div style={{ fontSize:12, color:"#888", background:"#f5f5f5", borderRadius:8, padding:"6px 10px", fontStyle:"italic" }}>Bv: "{v.example}"</div>
          </div>
        ))}
      </div>
    </div>
  );
}

