// ── SOURCES TAB ───────────────────────────────────────────────────────────────
function SourcesTab({ addXP, lang }) {
  const [setIdx, setSetIdx] = useState(0);
  const [answers, setAnswers] = useState({}); // qNum -> {text, revealed}
  const [expandedQ, setExpandedQ] = useState(null);
  const isAfr = lang !== "eng";
  const set = SOURCE_SETS[setIdx];
  const topic = TOPICS.find(t => t.id === set.topicId);

  const handleReveal = (qNum) => {
    setAnswers(a => ({ ...a, [qNum]: { ...a[qNum], revealed: true } }));
    addXP(5);
  };

  const handleText = (qNum, val) => {
    setAnswers(a => ({ ...a, [qNum]: { ...a[qNum], text: val } }));
  };

  const switchSet = (i) => {
    setSetIdx(i);
    setAnswers({});
    setExpandedQ(null);
  };

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:17, marginBottom:4 }}>
        📜 {isAfr ? "Brongebaseerde Oefening" : "Source-Based Practice"}
      </div>
      <div style={{ color:"#888", fontSize:13, marginBottom:14 }}>
        {isAfr
          ? "Presies soos die eksamen: lees die bron → beantwoord vrae → kontroleer met modelantwoord · +5 XP per onthulling"
          : "Exactly like the exam: read the source → answer questions → check model answer · +5 XP per reveal"}
      </div>

      {/* Source set selector */}
      <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:18 }}>
        {SOURCE_SETS.map((s, i) => {
          const t = TOPICS.find(x => x.id === s.topicId);
          return (
            <button key={s.id} onClick={() => switchSet(i)} style={{ background: setIdx===i ? t?.color||"#1a3a5c" : "#fff", border:`2px solid ${t?.color||"#1a3a5c"}${setIdx===i?"":"44"}`, borderRadius:12, padding:"12px 16px", cursor:"pointer", textAlign:"left", display:"flex", alignItems:"center", gap:12 }}>
              <span style={{ fontSize:22 }}>{s.emoji}</span>
              <div style={{ flex:1 }}>
                <div style={{ fontWeight:700, color: setIdx===i ? "#fff" : t?.color||"#1a3a5c", fontSize:14 }}>
                  {isAfr ? s.titleAfr : s.titleEng}
                </div>
                <div style={{ fontSize:11, color: setIdx===i ? "rgba(255,255,255,0.75)" : "#888", marginTop:2 }}>
                  {s.questions.length} {isAfr?"vrae":"questions"} · {s.questions.reduce((a,q)=>a+q.marks,0)} {isAfr?"punte":"marks"}
                </div>
              </div>
              {setIdx===i && <span style={{ color:"#fff", fontSize:16 }}>✓</span>}
            </button>
          );
        })}
      </div>

      {/* Source document */}
      <div style={{ background:"#1a3a5c", borderRadius:14, padding:16, marginBottom:18 }}>
        <div style={{ fontWeight:700, color:"#a8c4d8", fontSize:12, marginBottom:8, letterSpacing:1 }}>
          {isAfr ? set.source.labelAfr : set.source.labelEng}
        </div>
        <div style={{ background:"rgba(255,255,255,0.07)", borderRadius:10, padding:14, borderLeft:"4px solid rgba(255,255,255,0.3)" }}>
          <div style={{ color:"#e8f0f8", fontSize:14, lineHeight:2, fontStyle:"italic" }}>
            "{isAfr ? set.source.textAfr : set.source.textEng}"
          </div>
        </div>
        <div style={{ fontSize:11, color:"#5580a0", marginTop:8 }}>
          [{isAfr ? set.source.contextAfr : set.source.contextEng}]
        </div>
      </div>

      {/* Exam tips banner */}
      <div style={{ background:"#fff9e6", border:"1px solid #f0c04055", borderRadius:10, padding:12, marginBottom:16, fontSize:12, color:"#7d6608" }}>
        <span style={{ fontWeight:700 }}>{isAfr?"💡 Sleutelreël:":"💡 Key rule:"}</span>{" "}
        {isAfr
          ? "Vrae met 'gebruik Bron' → gebruik die teks hierbo. Vrae met 'eie kennis' → gebruik NIKS van die bron nie. Skryf jou antwoord in jou boek voor jy die model onthul."
          : "Questions saying 'use Source' → use the text above. Questions saying 'own knowledge' → use NOTHING from the source. Write your answer in your book before revealing the model."}
      </div>

      {/* Questions */}
      <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
        {set.questions.map((q, i) => {
          const ans = answers[q.num] || {};
          const isRevealed = !!ans.revealed;
          const isExpanded = expandedQ === q.num;

          return (
            <div key={q.num} style={{ background:"#fff", border:`2px solid ${isRevealed ? set.color : set.color+"44"}`, borderRadius:14, overflow:"hidden" }}>
              {/* Question header */}
              <button onClick={() => setExpandedQ(isExpanded ? null : q.num)} style={{ width:"100%", background:"none", border:"none", padding:"13px 16px", cursor:"pointer", textAlign:"left", display:"flex", gap:12, alignItems:"center" }}>
                <div style={{ width:36, height:36, borderRadius:10, background: isRevealed ? set.color : set.color+"22", display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                  <span style={{ fontWeight:800, color: isRevealed ? "#fff" : set.color, fontSize:13 }}>{q.num}</span>
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex", gap:6, alignItems:"center", marginBottom:3, flexWrap:"wrap" }}>
                    <span style={{ background:set.color+"15", color:set.color, borderRadius:6, padding:"1px 8px", fontSize:11, fontWeight:700 }}>
                      {isAfr ? q.typeAfr : q.typeEng}
                    </span>
                    <span style={{ background:"#f0f0f0", color:"#666", borderRadius:6, padding:"1px 8px", fontSize:11 }}>
                      {q.marks} {isAfr?"punt":"mark"}{q.marks!==1?"e":""}
                    </span>
                    {isRevealed && <span style={{ fontSize:11, color:"#117a65", fontWeight:700 }}>✅ {isAfr?"Modelantwoord gesien":"Model seen"}</span>}
                  </div>
                  <div style={{ fontSize:13, color:"#333", lineHeight:1.6, fontWeight:500 }}>
                    {isAfr ? q.qAfr : q.qEng}
                  </div>
                </div>
                <span style={{ color:"#ccc", fontSize:18, flexShrink:0 }}>{isExpanded?"↑":"↓"}</span>
              </button>

              {/* Expanded question body */}
              {isExpanded && (
                <div style={{ padding:"0 16px 16px", borderTop:`1px solid ${set.color}22` }}>
                  {/* Hint */}
                  <div style={{ background:"#eaf2fb", borderRadius:8, padding:"8px 12px", marginTop:10, marginBottom:12 }}>
                    <span style={{ fontWeight:700, color:"#1a5276", fontSize:12 }}>💡 {isAfr?"Wenk:":"Hint:"}</span>
                    <span style={{ fontSize:12, color:"#555" }}> {(isAfr ? q.hintsAfr : q.hintsEng).join(" ")}</span>
                  </div>

                  {/* Write answer prompt */}
                  {!isRevealed && (
                    <div style={{ background:"#f9f9f9", borderRadius:10, padding:12, marginBottom:12 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:"#555", marginBottom:6 }}>
                        ✏️ {isAfr?"Skryf jou antwoord in jou boek, dan optioneel 'n nota hier:":"Write your answer in your book, then optionally a note here:"}
                      </div>
                      <textarea
                        value={ans.text||""}
                        onChange={e=>handleText(q.num,e.target.value)}
                        placeholder={isAfr?"Opsionele nota vir jouself...":"Optional note to yourself..."}
                        rows={q.marks>=8?4:2}
                        style={{ width:"100%", padding:"8px 10px", borderRadius:8, border:"1.5px solid #e0e0e0", fontSize:13, boxSizing:"border-box", resize:"vertical", fontFamily:"Georgia, serif", lineHeight:1.6 }}
                      />
                    </div>
                  )}

                  {/* Reveal button */}
                  {!isRevealed ? (
                    <button onClick={()=>handleReveal(q.num)} style={{ width:"100%", background:set.color, color:"#fff", border:"none", borderRadius:10, padding:"11px 16px", fontWeight:700, fontSize:14, cursor:"pointer" }}>
                      🔍 {isAfr?"Wys modelantwoord (+5 XP)":"Show model answer (+5 XP)"}
                    </button>
                  ) : (
                    <div style={{ background:set.color+"0d", border:`1.5px solid ${set.color}33`, borderRadius:12, padding:14 }}>
                      <div style={{ fontWeight:700, color:set.color, fontSize:13, marginBottom:10 }}>
                        ✅ {isAfr?"Modelantwoord:":"Model answer:"}
                      </div>
                      <div style={{ fontSize:13, color:"#333", lineHeight:2, whiteSpace:"pre-line" }}>
                        {isAfr ? q.modelAfr : q.modelEng}
                      </div>
                      {/* Self-check for paragraph */}
                      {q.marks >= 8 && (
                        <div style={{ marginTop:12, paddingTop:12, borderTop:`1px dashed ${set.color}44` }}>
                          <div style={{ fontWeight:700, color:set.color, fontSize:12, marginBottom:6 }}>
                            🎯 {isAfr?"Selfkontrole — het jy die volgende ingesluit?":"Self-check — did you include the following?"}
                          </div>
                          {(isAfr ? q.hintsAfr : q.hintsEng).map((h,j)=>(
                            <div key={j} style={{ fontSize:12, color:"#555", marginBottom:4, display:"flex", gap:6 }}>
                              <span style={{ color:set.color }}>→</span>{h}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Progress */}
      {Object.keys(answers).some(k=>answers[k]?.revealed) && (
        <div style={{ background:"#eafaf1", border:"1.5px solid #117a6544", borderRadius:10, padding:12, marginTop:16 }}>
          <div style={{ fontSize:13, color:"#117a65", fontWeight:700 }}>
            ✅ {Object.values(answers).filter(a=>a?.revealed).length}/{set.questions.length} {isAfr?"vrae onthul":"questions revealed"} · {isAfr?"Goed gedoen!":"Well done!"}
          </div>
        </div>
      )}
    </div>
  );
}

// ── MAIN APP ──────────────────────────────────────────────────────────────────
export default function App() {
  const [tab, setTab] = useState(0);
  const [lang, setLang] = useState("afr");
  const [xp, setXp] = useState(0);
  const [streak] = useState(1);
  const [completedTopics, setCompletedTopics] = useState([]);
  const [flashcardsStudied, setFlashcardsStudied] = useState(0);
  const [quizScore, setQuizScore] = useState(0);

  // ── WEAK TOPIC RADAR state ────────────────────────────────────────────────
  // Each entry: { topicId, correct (bool), feel (null|"lost"|"ok"|"got") }
  const [performanceLog, setPerformanceLog] = useState([]);

  const logPerformance = useCallback((topicId, correct) => {
    setPerformanceLog(p => [...p, { topicId, correct, feel: null, ts: Date.now() }]);
  }, []);

  const logFeel = useCallback((feel, topicId) => {
    setPerformanceLog(p => {
      // attach feel to the most recent entry for this topic
      const idx = [...p].reverse().findIndex(e => e.topicId === topicId && e.feel === null);
      if (idx === -1) return [...p, { topicId, correct: true, feel, ts: Date.now() }];
      const real = p.length - 1 - idx;
      return p.map((e, i) => i === real ? { ...e, feel } : e);
    });
  }, []);

  // Compute radar scores per topic — blends objective (correct%) + subjective (feel)
  const radarScores = useCallback(() => {
    return TOPICS.map(t => {
      const entries = performanceLog.filter(e => e.topicId === t.id);
      if (entries.length === 0) return { topic: t, score: null, attempted: 0 };
      const correctPct = entries.filter(e => e.correct).length / entries.length;
      const feelEntries = entries.filter(e => e.feel !== null);
      const feelScore = feelEntries.length === 0 ? null
        : feelEntries.reduce((sum, e) => sum + (e.feel === "got" ? 1 : e.feel === "ok" ? 0.5 : 0), 0) / feelEntries.length;
      // blend: 70% objective, 30% subjective (if available)
      const blended = feelScore !== null ? correctPct * 0.7 + feelScore * 0.3 : correctPct;
      return { topic: t, score: blended, attempted: entries.length };
    });
  }, [performanceLog]);

  const addXP = useCallback((n) => setXp(x => x + n), []);
  const markTopicDone = useCallback((id) => setCompletedTopics(p => p.includes(id) ? p : [...p, id]), []);

  const T = UI[lang];
  // 6-tab simplified nav
  // 0=Home 1=Study 2=Practice 3=Afr 4=Sources 5=Guide
  const NAV = [
    ["🏠",T.tabHome],
    ["📖",T.tabStudy],
    ["🎯",T.tabPracticeNav],
    ["🌐",T.tabAfrNav],
    ["📜",T.tabSources],
    ["📋",T.tabGuideNav],
  ];

  return (
    <div style={{ fontFamily:"Georgia, serif", maxWidth:600, margin:"0 auto", background:"#f8f9fa", minHeight:"100vh", paddingBottom:80 }}>
      {/* Sticky header with language switcher */}
      <div style={{ background:"#1a3a5c", padding:"12px 16px", position:"sticky", top:0, zIndex:100 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div>
            <div style={{ fontWeight:800, color:"#fff", fontSize:14 }}>📚 {T.appTitle}</div>
            <div style={{ color:"#a8c4d8", fontSize:11 }}>{T.appSubtitle} · ⭐{xp} XP</div>
          </div>
          {/* Language switcher pill */}
          <div style={{ display:"flex", gap:3, background:"rgba(255,255,255,0.12)", borderRadius:10, padding:3 }}>
            {[["afr","🇿🇦 Afr"],["bil","🔀 Bil"],["eng","🇬🇧 Eng"]].map(([id,label])=>(
              <button key={id} onClick={()=>setLang(id)} style={{ padding:"5px 9px", borderRadius:8, border:"none", cursor:"pointer", background:lang===id?"#fff":"transparent", color:lang===id?"#1a3a5c":"#a8c4d8", fontWeight:lang===id?700:400, fontSize:11, transition:"all 0.2s" }}>
                {label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Tab content */}
      <div style={{ padding:"16px 16px 0" }}>
        {tab===0 && <HomeTab xp={xp} streak={streak} completedTopics={completedTopics} flashcardsStudied={flashcardsStudied} quizScore={quizScore} setTab={setTab} lang={lang} radarScores={radarScores} />}
        {tab===1 && <StudyHub addXP={addXP} markTopicDone={markTopicDone} completedTopics={completedTopics} flashcardsStudied={flashcardsStudied} setFlashcardsStudied={setFlashcardsStudied} logPerformance={logPerformance} logFeel={logFeel} lang={lang} />}
        {tab===2 && <PracticeHub addXP={addXP} quizScore={quizScore} setQuizScore={setQuizScore} logPerformance={logPerformance} logFeel={logFeel} lang={lang} />}
        {tab===3 && <AfrikaansTab addXP={addXP} lang={lang} />}
        {tab===4 && <SourcesTab addXP={addXP} lang={lang} />}
        {tab===5 && <GuideHub setTab={setTab} lang={lang} />}
      </div>

      {/* Bottom nav */}
      <div style={{ position:"fixed", bottom:0, left:0, right:0, background:"#fff", borderTop:"1px solid #e0e0e0", display:"flex", zIndex:100 }}>
        {NAV.map(([icon,label],i)=>(
          <button key={i} onClick={()=>setTab(i)} style={{ flex:1, background:"none", border:"none", padding:"10px 1px", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:2 }}>
            <span style={{ fontSize:tab===i?21:17, transition:"font-size 0.15s" }}>{icon}</span>
            <span style={{ fontSize:8, color:tab===i?"#1a3a5c":"#bbb", fontWeight:tab===i?700:400 }}>{label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

