                        {entry.figure && <span style={{ background:"#7b241c15", color:"#7b241c", borderRadius:6, padding:"1px 7px", fontSize:11 }}>👤</span>}
                        {linked && <span style={{ background:"#6c348315", color:"#6c3483", borderRadius:6, padding:"1px 7px", fontSize:11 }}>🌐</span>}
